(function(){
  function isOurs(el){
    if(!el||el.nodeType!==1)return false;
    if(el.tagName==='SCRIPT'||el.tagName==='STYLE'||el.tagName==='LINK'||el.tagName==='META')return true;
    var id=el.id||'';
    if(id==='demoBanner'||id==='resultsBody'||id==='nlca-snav')return true;
    var cls=el.className||'';
    if(typeof cls==='string'){
      if(cls.indexOf('res-nav')>-1||cls.indexOf('results-footer')>-1||cls.indexOf('results-body')>-1||cls.indexOf('demo-banner')>-1)return true;
    }
    /* Preserve our own injected nav (sidebar) which lives at body level */
    if(el.tagName==='NAV'&&(cls.indexOf('res-nav')>-1||id==='nlca-snav'))return true;
    /* Preserve our own footer */
    if(el.tagName==='FOOTER'&&cls.indexOf('results-footer')>-1)return true;
    /* Keep any element that contains our content */
    if(el.querySelector&&el.querySelector('#resultsBody,#demoBanner,.results-footer,.res-nav'))return true;
    return false;
  }
  function escapeGHL(){
    var body=document.body;
    var anchor=document.getElementById('resultsBody')||document.getElementById('demoBanner');
    if(anchor&&anchor.parentElement!==body){
      var wrap=anchor.parentElement;
      while(wrap&&wrap.parentElement!==body)wrap=wrap.parentElement;
      if(wrap){
        var frag=document.createDocumentFragment();
        while(wrap.firstChild)frag.appendChild(wrap.firstChild);
        body.insertBefore(frag,wrap);
        wrap.parentNode.removeChild(wrap);
      }
    }
    /* Remove any GHL sibling sections (white strips above/below our content) */
    Array.prototype.slice.call(body.children).forEach(function(child){
      if(!isOurs(child)){
        try{child.parentNode.removeChild(child);}catch(e){}
      }
    });
  }
  window.__nlcaEscapeGHL=escapeGHL;
  if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',escapeGHL);}
  else{escapeGHL();}
  /* Catch GHL late-injected elements */
  setTimeout(escapeGHL,100);
  setTimeout(escapeGHL,500);
  setTimeout(escapeGHL,1500);
  if(window.MutationObserver){
    var mo=new MutationObserver(function(){escapeGHL();});
    mo.observe(document.body,{childList:true});
  }
})();

const SEV_LABEL  = { critical: 'Critical', warning: 'Needs Work', ok: 'Strong' };
const ARROW      = `<svg width="13" height="13" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M13 7l5 5m0 0l-5 5m5-5H6"/></svg>`;
const MODULE_SHORT = {
  'Foundations & Psychology': 'Builds the psychology, lead-qualification filter, and the exact handoff structure that separates clinical from financial presentations — so your TC enters the room with authority.',
  'The 8-Step Consult Flow': 'All eight steps of the financial consultation scripted from open to signed plan. Value anchoring, investment presentation, financing pivot, and the same-day close — drilled live every session.',
  'Objection Mastery': 'Word-for-word responses to every hesitation that ends a case: the financing objection, the spouse conversation, "let me think about it," and the patient who leaves without a clear reason.'
};

function buildResults(answers) {
  const a = answers;
  const volMap  = { '5-14': 10, '15-29': 22, '30-49': 40, '50plus': 60 };
  const rateMap = { 'u20': 0.15, '20-40': 0.30, '41-60': 0.50, '61plus': 0.65 };
  const showupMap = { 'u60': 0.50, '61-79': 0.70, '80plus': 0.85 };
  const vol     = volMap[a.q1]  || 10;
  const rate    = rateMap[a.q2] || 0.30;
  const showup  = showupMap[a.q6] || 0.80;
  const caseVal = 25000;
  const isLowVol        = a.q1 === '0-4';
  const isHighPerformer = rate >= 0.65;
  const monthlyGap      = Math.round(Math.max(0, 0.70 - rate) * vol * caseVal);
  const annualGap       = monthlyGap * 12;
  console.log('[NLCA] Calculation:', {
    'q1 (raw)': a.q1, 'volMap match': volMap[a.q1], 'vol (used)': vol,
    'q2 (raw)': a.q2, 'rateMap match': rateMap[a.q2], 'rate (used)': rate,
    'q6 (raw)': a.q6, 'showupMap match': showupMap[a.q6], 'showup (used)': showup,
    'monthlyGap': monthlyGap, 'annualGap': annualGap
  });

  /* SEV — matches original report.html logic exactly. Returns 'ok' for non-triggering answers,
     so cards dynamically appear/disappear based on real quiz responses (0–5 cards). */
  const SEV = {
    vol:   a.q1 === '5-14' ? 'warning' : 'ok',
    rate:  (a.q2 === 'u20' || a.q2 === '20-40') ? 'critical' : a.q2 === '41-60' ? 'warning' : 'ok',
    pres:  (a.q3 === 'doctor-full' || a.q3 === 'doctor-led-fin') ? 'critical' : a.q3 === 'tc-no-script' ? 'warning' : 'ok',
    block: (a.q4 === 'financing' || a.q4 === 'spouse' || a.q4 === 'sameday' || a.q4 === 'close') ? 'critical' : a.q4 === 'leads' ? 'warning' : 'ok',
    mkt:   a.q5 === 'o15' ? 'warning' : 'ok'
  };

  const TRAIT_META = [
    { key: 'rate',  label: 'Close Rate',
      consequence: {
        critical: 'Seven of every ten qualified patients walk out without signing.',
        warning:  'Half of your qualified consults are ending without a plan signed.',
        ok:       'Closing well. The remaining points decide elite territory.'
      } },
    { key: 'pres',  label: 'Presentation Quality',
      consequence: {
        critical: 'The clinical conversation lands. The financial one does not.',
        warning:  'Strong on technical, soft on investment, missing the close.',
        ok:       'Solid presentation discipline. Refinements only from here.'
      } },
    { key: 'block', label: 'Financial Handoff',
      consequence: {
        critical: 'The doctor is leading the financial conversation. Patients defer.',
        warning:  'A handoff is happening, but the TC arrives without authority.',
        ok:       'Clean handoff. Clinical exits, financial owns the room.'
      } },
    { key: 'vol',   label: 'Case Loss Pattern',
      consequence: {
        critical: 'Cases are dying at the moment of decision, not the moment of presentation.',
        warning:  'Specific objections recurring without a scripted response.',
        ok:       'No recurring loss pattern. The team is closing what walks in.'
      } },
    { key: 'mkt',   label: 'Ad Spend Ratio',
      consequence: {
        critical: 'Marketing spend exceeds your conversion economics. Spending more loses more.',
        warning:  'Spend ratio above healthy. Volume cannot offset a leaky close rate.',
        ok:       'Marketing spend is in a healthy range relative to revenue.'
      } }
  ];
  function buildTraitBars() {
    const gradeFor = (key, sev) => {
      if (key === 'rate') return Math.round(rate * 100) + '%';
      return { critical: 'D', warning: 'C+', ok: 'A−' }[sev];
    };
    const counts = TRAIT_META.reduce((acc, m) => { acc[SEV[m.key]] = (acc[SEV[m.key]] || 0) + 1; return acc; }, {});
    const verdictParts = [];
    if (counts.critical) verdictParts.push(`<strong>${counts.critical}</strong> critical`);
    if (counts.warning)  verdictParts.push(`<strong>${counts.warning}</strong> needing work`);
    if (counts.ok)       verdictParts.push(`<strong>${counts.ok}</strong> strong`);
    const verdict = verdictParts.join(', ');
    return `
      <div class="trait-verdict">
        <span class="tv-rule"></span>
        <p>The diagnosis reads <em>${verdict}</em>. Every gap below maps to a specific moment inside the consult, not your ad spend.</p>
      </div>
      <div class="trait-cards">` +
        TRAIT_META.map(m => {
          const sev = SEV[m.key];
          const grade = gradeFor(m.key, sev);
          const sevLabel = SEV_LABEL[sev];
          return `<article class="trait-card trait-card--${sev}">
            <header class="tc-head">
              <span class="tc-sev">${sevLabel}</span>
              <h3 class="tc-label">${m.label}</h3>
              <div class="tc-grade">${grade}</div>
            </header>
            <div class="tc-track" aria-hidden="true">
              <div class="tc-fill sev-${sev}"></div>
              <span class="tc-benchmark" style="left:88%;"></span>
              <span class="tc-benchmark-label">Benchmark</span>
            </div>
            <p class="tc-consequence">${m.consequence[sev]}</p>
          </article>`;
        }).join('') +
      `</div>`;
  }

  const moduleMap = new Map();

  const AREA_SLUG = {
    'Full Arch Volume':  'volume',
    'Plan Close Rate':   'close-rate',
    'Financial Handoff': 'financial-handoff',
    'Case Loss Pattern': 'case-loss',
    'Ad Spend Ratio':    'ad-spend',
  };

  function card(sev, area, problem, impact, fixSteps, moduleName, nlcaDesc) {
    if (!moduleMap.has(moduleName)) moduleMap.set(moduleName, []);
    moduleMap.get(moduleName).push({ sev, area });
    const areaSlug = AREA_SLUG[area] || area.toLowerCase().replace(/\s+/g, '-');
    const li = fixSteps.map(s => `<li>${s}</li>`).join('');
    const nlcaBlock = nlcaDesc ? `
        <details class="manual-toggle nlca-toggle">
          <summary>What you get with NLCA</summary>
          <div class="nlca-detail">${nlcaDesc}</div>
        </details>` : '';
    return `<div class="section-card" data-sev="${sev}" data-area="${areaSlug}">
      <div class="card-inner">
        <div class="section-badge-row">
          <span class="sev-chip sev-${sev}">${SEV_LABEL[sev]}</span>
          <span class="section-area">${area}</span>
        </div>
        <div class="section-problem">${problem}</div>
        <div class="section-impact">${impact}</div>
        <div class="card-toggles">
          <details class="manual-toggle" open>
            <summary>What you can fix yourself</summary>
            <ul class="fix-steps">${li}</ul>
          </details>${nlcaBlock}
        </div>
      </div>
    </div>`;
  }

  function buildLearningPath() {
    if (moduleMap.size === 0) return '';
    /* ── NLCA FRAMEWORK ── Three-tier operating system rendered bottom-up:
       PSYCHOLOGY (foundation) → PROCESS (8-step) → MASTERY (close) → 70% target crown */
    const PILLARS = {
      'Foundations & Psychology': {
        slug: 'psychology',
        tier: 'Foundation',
        tagline: 'The room before the consult begins.',
        items: ['Three Cs qualification filter', 'Lead-call screening before booking', 'Clinical-to-financial handoff', 'TC authority and room presence']
      },
      'The 8-Step Consult Flow': {
        slug: 'process',
        tier: 'Engine',
        tagline: 'The eight steps from open to signed plan.',
        items: ['Value anchoring before price', 'Investment presentation', 'Financing pivot, drilled live', 'Same-day decision protocol']
      },
      'Objection Mastery': {
        slug: 'mastery',
        tier: 'Close',
        tagline: 'The ten seconds that decide every case.',
        items: ['Financing objection response', 'The spouse-decision conversation', '"Let me think about it"', 'The walk-away pattern']
      }
    };
    const ORDER = ['Foundations & Psychology', 'The 8-Step Consult Flow', 'Objection Mastery'];
    const sorted = ORDER.filter(m => moduleMap.has(m));
    // Render top-down: Mastery → Process → Psychology (so foundation reads at the bottom)
    const tiersHtml = [...sorted].reverse().map((name, idx) => {
      const p = PILLARS[name];
      const findings = moduleMap.get(name);
      const tags = findings.map(f => `<span class="lp-tag lp-${f.sev}">${f.area}</span>`).join('');
      const itemsHtml = p.items.map(it => `<li>${it}</li>`).join('');
      const tierNum = String(sorted.length - idx).padStart(2, '0');
      return `<div class="fw-tier fw-tier--${p.slug}">
        <div class="fw-tier-head">
          <span class="fw-tier-num">${tierNum}</span>
          <div class="fw-tier-title">
            <span class="fw-tier-layer">${p.tier} layer</span>
            <div class="fw-tier-name">${name}</div>
            <p class="fw-tier-tagline">${p.tagline}</p>
          </div>
        </div>
        <ul class="fw-tier-list">${itemsHtml}</ul>
        ${tags ? `<div class="fw-tier-tags">Addresses: ${tags}</div>` : ''}
      </div>`;
    }).join('<div class="fw-rise" aria-hidden="true"></div>');

    return `<div class="learning-path">
      <div class="lp-inner">
        <div class="ghost-num" aria-hidden="true">04</div>
        <div class="section-num-row">
          <div class="section-num">4</div>
          <div class="section-label-tag">The Method</div>
        </div>
        <h2 class="section-heading">The NLCA Framework</h2>
        <p class="section-intro">A three-layer operating system for the consult room, built from eight years inside high-performing full-arch practices. Every layer addresses a specific gap in how your team converts qualified patients.</p>
        <figure class="fw-proof">
          <div class="fw-proof-photo">
            <img src="https://assets.cdn.filesafe.space/vdi6H8skwmbrWBAz1f6X/media/6a074b1e937389dca0560323.jpg" alt="Stacy Farley coaching a full-arch consult team live" loading="lazy" width="1182" height="665">
          </div>
          <figcaption class="fw-proof-caption">
            <span class="fw-proof-rule"></span>
            <span class="fw-proof-label">Live coaching room · Nashville workshop</span>
            <span class="fw-proof-name">This is the room. Twice a month, from inside your practice.</span>
          </figcaption>
        </figure>
        <div class="fw-framework">
          <div class="fw-crown">
            <span class="fw-crown-eyebrow">Operating Outcome</span>
            <div class="fw-crown-target">70<span class="fw-pct">%</span></div>
            <div class="fw-crown-label">Close rate benchmark, every consult, every month.</div>
          </div>
          <div class="fw-rise fw-rise--top" aria-hidden="true"></div>
          <div class="fw-tiers">${tiersHtml}</div>
        </div>
        <div class="lp-cta-wrap">
          <a href="/nextlevel-124405" target="_blank" rel="noopener noreferrer" class="lp-cta-btn">
            Close my $${monthlyGap.toLocaleString()}/mo gap — $295/mo ${ARROW}
          </a>
          <p class="lp-fine">$295/month · Live with Stacy twice a month · No long-term contract</p>
        </div>
      </div>
    </div>`;
  }

  function buildInside() {
    const cards = [
      { name: 'Live with Stacy, twice a month', desc: 'Two coached working sessions every month. Real consults, real objections, real plans. Stacy in the room with your team.' },
      { name: 'Recording library + transcripts', desc: 'Every session recorded and indexed. Miss a date or onboard a new TC, drop them into the replay catalog and they catch up in days.' },
      { name: 'Whole team joins from your office', desc: 'TC, treatment plan presenter, financial coordinator, and dentist. One subscription covers the entire room.' },
      { name: 'Scripts, frameworks, financing language', desc: 'The exact 8-step consult flow, objection responses, and financing conversations Stacy used to close 40 to 50 arches a month.' }
    ];
    const items = cards.map((c, i) => `<div class="inside-card">
      <div class="inside-num">${String(i + 1).padStart(2, '0')}</div>
      <div class="inside-name">${c.name}</div>
      <p class="inside-desc">${c.desc}</p>
    </div>`).join('');
    return `<div class="inside-band">
      <div class="ghost-num" aria-hidden="true">05</div>
      <div class="section-num-row">
        <div class="section-num">5</div>
        <div class="section-label-tag">What's Inside Every Month</div>
      </div>
      <h2 class="section-heading">Every month inside NLCA.</h2>
      <p class="section-intro">A live coaching room, not a course library. Built so the whole consult team practices the conversation that closes the case.</p>
      <div class="inside-grid">${items}</div>
    </div>`;
  }

  function buildInvest(ctaLabel) {
    const faqs = [
      { q: 'What exactly is NLCA?', a: 'Live virtual coaching for full-arch dental practices. Stacy and her team run two working sessions a month with your TC and treatment team. Not a course, not a workbook. A coached rehearsal of the conversation that closes the case.' },
      { q: 'Who can join from my team?', a: 'The whole consult team. TC, treatment plan presenter, financial coordinator, and the dentist. One subscription covers everyone in the practice. Sessions are recorded so anyone who misses a date catches up later.' },
      { q: 'How long is the commitment?', a: 'Month to month. Cancel any month with no contract and no questions asked. Most practices stay because one closed arch case covers the membership for the entire year.' },
      { q: 'What if we miss a session?', a: 'Every session is recorded and added to your replay library within 24 hours, with transcripts and timestamps. You can also bring questions to the next live session for direct coaching.' },
      { q: 'How is this different from other dental coaching?', a: 'Stacy closed 40 to 50 full-arch cases a month at a 70% close rate for eight years, on a 5% marketing budget. The scripts and frameworks come from her actual practice, not theory or generalized sales training.' },
      { q: 'When does my team get started?', a: 'You join the next live session as soon as you enroll. Your team gets immediate access to the replay library and the consult flow workbook the moment payment clears.' },
      { q: 'Is this only for full-arch practices?', a: 'Yes. NLCA is built specifically for practices presenting and financing full-arch implant cases. The frameworks, financing scripts, and objection responses are all calibrated for the full-arch consult.' },
      { q: 'What if it is not the right fit?', a: 'Cancel any month. There is no contract. If the first session does not deliver value to your team, you will not be the first practice to walk away, and we want it that way.' }
    ];
    const items = faqs.map(f => `<details class="faq-item">
      <summary>${f.q}</summary>
      <div class="faq-answer">${f.a}</div>
    </details>`).join('');
    return `<div class="invest-band">
      <div class="ghost-num" aria-hidden="true">06</div>
      <div class="section-num-row">
        <div class="section-num">6</div>
        <div class="section-label-tag">Investment + Questions</div>
      </div>
      <h2 class="section-heading">One case covers the year.</h2>
      <p class="section-intro">No contract. No long onboarding. Cancel any month with no questions.</p>
      <div class="invest-grid">
        <div class="price-card">
          <span class="price-eyebrow">Monthly</span>
          <div class="price-amount">$295<span class="price-unit">/month</span></div>
          <p class="price-tag">One closed arch case covers the entire year.</p>
          <ul class="price-list">
            <li>Two live coaching sessions every month with Stacy</li>
            <li>Recording library, transcripts, and the consult flow workbook</li>
            <li>Whole team joins. TC, presenter, financial coordinator, dentist</li>
            <li>Direct coaching on your actual consults, not generic theory</li>
            <li>Cancel any month, no contract</li>
          </ul>
          <a href="/nextlevel-124405" target="_blank" rel="noopener noreferrer" class="price-cta">
            ${ctaLabel} ${ARROW}
          </a>
          <p class="price-fine">$295/month · Cancel anytime · Live with Stacy twice a month</p>
        </div>
        <div class="faq-col">
          <span class="faq-eyebrow">Common Questions</span>
          <h3 class="faq-headline">What practices ask before they enroll.</h3>
          <p class="faq-sub">If your question is not here, send it to the same address that delivered this report and you will hear back the same day.</p>
          <div class="faq-list">${items}</div>
        </div>
      </div>
    </div>`;
  }

  function stacyPull(quote, attr) {
    return `<div class="stacy-pull">
      <span class="stacy-pull-mark">"</span>
      <p class="stacy-pull-text">${quote}</p>
      <div class="stacy-pull-attr"><strong>${attr}</strong> · Full Arch Sales Experts</div>
    </div>`;
  }

  /* ── Cards ── */
  const cards = [];

  if (SEV.vol === 'warning') {
    cards.push(card('warning', 'Full Arch Volume',
      'You have consultations coming in — but not enough runway to absorb a leaky close rate.',
      `At 10 consultations/month, the difference between your current close rate and Stacy's 70% benchmark is <strong>$${Math.round((0.70 - rate) * 10 * caseVal).toLocaleString()}/month</strong>. Fixing conversion now means every new consultation you add compounds at 70% instead of your current rate.`,
      [
        'Activate referral partnerships with local implant reps and oral surgeons — they see viable full arch candidates daily',
        'Run a reactivation campaign to your existing patient base: offer a no-cost full arch evaluation for 30 days',
        'Tighten your lead call to screen for the Three Cs — Cash, Credit, or Co-signer — before booking a consultation slot'
      ],
      'Foundations & Psychology',
