/* ── Bootstrap ── */
document.addEventListener('DOMContentLoaded', () => {
  let answers = null;

  /* ── GHL Custom Values (server-rendered by GHL) ──
       Field names match submitToGHL() in squeeze_nohdr.html:
       consultations_per_month, close_rate, financial_handoff,
       case_loss_pattern, marketing_spend                        */
  const ghlValues = {
    q1: '{{contact.consultations_per_month}}',
    q2: '{{contact.close_rate}}',
    q3: '{{contact.financial_handoff}}',
    q4: '{{contact.case_loss_pattern}}',
    q5: '{{contact.marketing_spend}}',
    q6: '{{contact.show_up_rate}}'
  };

  /* ── URL parameter fallback (for redirect-based flows) ──
       Robust: tries search, hash, then raw href in case GHL strips/moves them. */
  function getAllParams() {
    const href = window.location.href || '';
    /* Strategy 1: standard search */
    let qs = window.location.search || '';
    /* Strategy 2: hash params (GHL sometimes rewrites ? to #) */
    if (!qs || qs.length <= 1) {
      const hash = window.location.hash || '';
      if (hash.indexOf('?') > -1) qs = hash.substring(hash.indexOf('?'));
      else if (hash.indexOf('=') > -1) qs = '?' + hash.replace(/^#/, '');
    }
    /* Strategy 3: parse raw href for ?key=value pairs anywhere */
    if (!qs || qs.length <= 1) {
      const m = href.match(/[?&](q[1-6]=[^&#]*(?:&q[1-6]=[^&#]*)*)/);
      if (m) qs = '?' + m[1];
    }
    return new URLSearchParams(qs);
  }
  const params = getAllParams();
  console.log('[NLCA] URL params detected:', Object.fromEntries(params.entries()));
  function fromParams() {
    const q1 = params.get('q1'), q2 = params.get('q2'), q3 = params.get('q3'),
          q4 = params.get('q4'), q5 = params.get('q5'), q6 = params.get('q6');
    if (q1 && q2 && q3 && q4 && q5 && q6) return { q1, q2, q3, q4, q5, q6 };
    return null;
  }

  /* ── ?clear=1 lets you wipe cached data for fresh testing ── */
  if (window.location.search.indexOf('clear=1') > -1 || window.location.hash.indexOf('clear=1') > -1) {
    try {
      localStorage.removeItem('nlca_report');
      if (window.top && window.top !== window) {
        try { window.top.localStorage.removeItem('nlca_report'); } catch(_) {}
      }
      console.log('[NLCA] Cache cleared via ?clear=1');
    } catch(e) {}
  }

  /* ── localStorage: ONE-TIME USE ─────────────────────────────────────────
     Squeeze writes 'nlca_report' before redirect. Report reads it once,
     then immediately deletes it. This prevents stale data on revisit and
     stops one person's answers from showing for another on shared devices. */
  const MAX_AGE_MS = 1000 * 60 * 60; /* 1 hour — covers redirect window only */
  function fromLocalStorage() {
    let raw = null;
    try {
      raw = localStorage.getItem('nlca_report');
      if (!raw) return null;
      const data = JSON.parse(raw);
      const a = data && data.answers;
      if (!a || !a.q1 || !a.q2 || !a.q3 || !a.q4 || !a.q5 || !a.q6) {
        /* Malformed — clean up and bail */
        try { localStorage.removeItem('nlca_report'); } catch(_) {}
        return null;
      }
      /* Freshness check — ignore stale data older than 1 hour */
      if (data.savedAt && (Date.now() - data.savedAt > MAX_AGE_MS)) {
        try { localStorage.removeItem('nlca_report'); } catch(_) {}
        console.log('[NLCA] localStorage data is stale (>1hr), discarded');
        return null;
      }
      /* ONE-TIME USE: consume and delete */
      try {
        localStorage.removeItem('nlca_report');
        if (window.top && window.top !== window) {
          try { window.top.localStorage.removeItem('nlca_report'); } catch(_) {}
        }
      } catch(_) {}
      console.log('[NLCA] Consumed localStorage answers (deleted after read):', a);
      return a;
    } catch(e) {
      console.warn('[NLCA] localStorage read failed:', e);
      /* Try to clean up bad data */
      try { localStorage.removeItem('nlca_report'); } catch(_) {}
    }
    return null;
  }

  /* Priority: localStorage > URL params > GHL custom values > demo fallback */
  const _debug = {
    href: window.location.href,
    search: window.location.search,
    hash: window.location.hash,
    paramsParsed: Object.fromEntries(params.entries()),
    localStorageRaw: (function(){ try { return localStorage.getItem('nlca_report'); } catch(e) { return 'ERROR: ' + e.message; } })(),
    ghlRaw: ghlValues,
    source: null
  };

  answers = fromLocalStorage();
  if (answers) _debug.source = 'localStorage';

  if (!answers) {
    answers = fromParams();
    if (answers) { _debug.source = 'URL params'; console.log('[NLCA] Using URL params:', answers); }
  }

  if (!answers) {
    const isGHLRendered = ghlValues.q1 && !ghlValues.q1.includes('{{');
    if (isGHLRendered) {
      answers = ghlValues;
      _debug.source = 'GHL custom values';
      console.log('[NLCA] Using GHL custom values:', answers);
    }
  }

  if (!answers) {
    /* Demo mode — randomize so dynamism is visible per pageview */
    const demoPool = {
      q1: ['5-14', '15-29', '30-49', '50plus'],
      q2: ['u20', '20-40', '41-60', '61plus'],
      q3: ['doctor-full', 'doctor-led-fin', 'tc-no-script', 'tc-scripted'],
      q4: ['close'],
      q5: ['u5', '5-15', 'o15'],
      q6: ['u60', '61-79', '80plus']
    };
    const pick = arr => arr[Math.floor(Math.random() * arr.length)];
    answers = { q1: pick(demoPool.q1), q2: pick(demoPool.q2), q3: pick(demoPool.q3), q4: 'close', q5: pick(demoPool.q5), q6: pick(demoPool.q6) };
    _debug.source = 'demo (random)';
    document.getElementById('demoBanner').classList.add('visible');
    /* Replace demo banner text with diagnostic info so user sees why */
    const banner = document.getElementById('demoBanner');
    if (banner) {
      banner.innerHTML =
        '<strong>Demo mode</strong> — no real quiz data found. Diagnostic:' +
        '<br>• URL search: <code>' + (_debug.search || '(empty)') + '</code>' +
        '<br>• URL hash: <code>' + (_debug.hash || '(empty)') + '</code>' +
        '<br>• Parsed params: <code>' + JSON.stringify(_debug.paramsParsed) + '</code>' +
        '<br>• localStorage: <code>' + (_debug.localStorageRaw ? _debug.localStorageRaw.substring(0,120) + '…' : '(empty)') + '</code>' +
        '<br>• GHL values: <code>' + JSON.stringify(_debug.ghlRaw) + '</code>';
    }
    console.log('[NLCA] Falling back to demo mode. Debug:', _debug);
  }
  window.__nlcaDebug = _debug;
  console.log('[NLCA] Final source:', _debug.source, '| Answers:', answers);

  console.log('[NLCA] Final answers used:', answers);
  buildResults(answers);

  // Toggle click delegation — any click on the box opens it
  document.addEventListener('click', e => {
    const toggle = e.target.closest('.manual-toggle');
    if (toggle && !e.target.closest('summary') && !e.target.closest('.fix-steps') && !e.target.closest('.nlca-detail')) {
      toggle.open = !toggle.open;
    }
  });

  // Section nav — built entirely in JS, injected into <head>/<body>
  // so GHL container transforms cannot affect position:fixed
  (function() {
    if (window.innerWidth <= 900) return;

    // Inject styles into <head> — outside GHL scope
    var s = document.createElement('style');
    s.textContent = [
      '#nlca-snav{position:fixed!important;left:16px!important;top:50%!important;',
      'transform:translateY(-50%)!important;width:auto!important;max-width:160px!important;',
      'display:flex!important;flex-direction:column!important;gap:2px!important;',
      'z-index:99999!important;opacity:0;transition:opacity .4s;',
      'background:rgba(10,10,40,0.85)!important;',
      'backdrop-filter:blur(12px) saturate(1.4)!important;',
      '-webkit-backdrop-filter:blur(12px) saturate(1.4)!important;',
      'border:1px solid rgba(22,103,232,0.20)!important;',
      'border-radius:14px!important;padding:10px 8px!important;',
      'box-shadow:0 4px 24px -6px rgba(0,0,0,.30),0 1px 4px rgba(0,0,0,.15)!important;',
      'pointer-events:auto!important;}',
      '#nlca-snav a{display:flex!important;align-items:center!important;gap:10px!important;',
      'padding:5px 8px!important;text-decoration:none!important;border-radius:6px!important;',
      'cursor:pointer!important;transition:background .12s!important;}',
      '#nlca-snav a:hover{background:rgba(22,103,232,.15)!important;}',
      '#nlca-snav .nd{width:6px!important;height:6px!important;border-radius:50%!important;',
      'background:rgba(100,116,139,.5)!important;flex-shrink:0!important;transition:all .2s!important;}',
      '#nlca-snav a.on .nd{background:#1667E8!important;width:8px!important;height:8px!important;',
      'box-shadow:0 0 0 3px rgba(22,103,232,.2)!important;}',
      '#nlca-snav a:hover .nd{background:#1667E8!important;}',
      '#nlca-snav .nl{font-size:11px!important;font-weight:700!important;',
      'color:rgba(255,255,255,.50)!important;letter-spacing:.03em!important;',
      'white-space:nowrap!important;font-family:-apple-system,BlinkMacSystemFont,"Inter",sans-serif!important;',
      'transition:color .15s!important;}',
      '#nlca-snav a.on .nl,#nlca-snav a:hover .nl{color:#FFFFFF!important;}',
      /* Hide entirely on mobile/tablet */
      '@media (max-width:900px){#nlca-snav{display:none!important;}}'
    ].join('');
    document.head.appendChild(s);

    // Build nav data from sections
    var sections = [];
    var add = function(el, label) { if (el) sections.push({ el: el, label: label }); };
    add(document.querySelector('.results-header'), 'Overview');
    document.querySelectorAll('.report-section').forEach(function(el, i) {
      add(el, ['Metrics','Revenue Gap','Findings'][i] || 'Section');
    });
    add(document.querySelector('.learning-path'),     'Your Path');
    add(document.querySelector('.social-proof-band'), 'Proof');
    add(document.querySelector('.video-testimonials'),'Results');
    add(document.querySelector('.cta-section'),       'Join NLCA');

    // Create nav element and append directly to body
    var nav = document.createElement('nav');
    nav.id = 'nlca-snav';
    nav.setAttribute('aria-label', 'Report sections');
    sections.forEach(function(sec, i) {
      sec.el.setAttribute('data-snav', i);
      var a = document.createElement('a');
      a.href = '#';
      a.innerHTML = '<span class="nd"></span><span class="nl">' + sec.label + '</span>';
      a.addEventListener('click', function(e) {
        e.preventDefault();
        sec.el.scrollIntoView({ behavior: 'smooth', block: 'start' });
      });
      nav.appendChild(a);
    });
    document.body.appendChild(nav);

    // Fade in after append
    requestAnimationFrame(function() { nav.style.opacity = '1'; });

    // Active state via IntersectionObserver
    var links = nav.querySelectorAll('a');
    var obs = new IntersectionObserver(function(entries) {
      entries.forEach(function(e) {
        if (!e.isIntersecting) return;
        var i = e.target.getAttribute('data-snav');
        links.forEach(function(l) { l.classList.remove('on'); });
        if (links[i]) links[i].classList.add('on');
      });
    }, { rootMargin: '-25% 0px -65% 0px' });
    sections.forEach(function(sec) { obs.observe(sec.el); });
  })();

  const io = new IntersectionObserver((entries) => {
    entries.forEach(e => { if (e.isIntersecting) { e.target.classList.add('visible'); io.unobserve(e.target); } });
  }, { threshold: 0.07 });
  document.querySelectorAll('.report-section, .learning-path, .social-proof-band').forEach(el => {
    el.classList.add('stagger-in');
    io.observe(el);
  });

});
</script>

